// ═══════════════════════════════════════════════════════════════════
// GALAXY BACKGROUND
// ═══════════════════════════════════════════════════════════════════
(function initGalaxy() {
  const canvas = document.getElementById('galaxy-canvas');
  const ctx = canvas.getContext('2d');
  let W, H;
  function resize() { W = canvas.width = window.innerWidth; H = canvas.height = window.innerHeight; }
  resize();
  window.addEventListener('resize', () => { resize(); stars.forEach(s => { s.ox = s.x = Math.random()*W; s.oy = s.y = Math.random()*H; }); });
  let mouseX = -9999, mouseY = -9999;
  window.addEventListener('mousemove', e => { mouseX = e.clientX; mouseY = e.clientY; });
  const STAR_COUNT = 280;
  const stars = Array.from({ length: STAR_COUNT }, () => {
    const x = Math.random()*window.innerWidth, y = Math.random()*window.innerHeight;
    return { ox:x,oy:y,x,y,vx:0,vy:0,r:Math.random()*1.7+0.3,alpha:Math.random()*0.6+0.3,twinkleSpeed:Math.random()*0.9+0.3,twinkleOffset:Math.random()*Math.PI*2,hue:190+Math.random()*45,mass:Math.random()*0.4+0.6 };
  });
  const NEBULAS=[{cx:.18,cy:.28,rx:.32,ry:.22,color:'91,200,245',alpha:.042},{cx:.76,cy:.65,rx:.28,ry:.20,color:'100,160,255',alpha:.035},{cx:.50,cy:.50,rx:.42,ry:.30,color:'60,100,200',alpha:.022},{cx:.86,cy:.18,rx:.20,ry:.16,color:'120,200,255',alpha:.032},{cx:.12,cy:.76,rx:.22,ry:.18,color:'80,140,230',alpha:.028}];
  const ORBS=[{cx:.20,cy:.35,r:95,color:'80,160,255',alpha:.055},{cx:.80,cy:.62,r:75,color:'91,200,245',alpha:.065},{cx:.50,cy:.18,r:60,color:'130,190,255',alpha:.048}];
  const shooters=[];
  function spawnShooter(){shooters.push({x:Math.random()*.65,y:Math.random()*.45,len:90+Math.random()*130,speed:.0016+Math.random()*.002,progress:0,alpha:.65+Math.random()*.35,angle:Math.PI/5+(Math.random()-.5)*.3});}
  setInterval(()=>{if(shooters.length<3)spawnShooter();},3000); spawnShooter();
  const REPEL_RADIUS=120,REPEL_FORCE=6.5,FRICTION=.88,RETURN_FORCE=.045; let t=0;
  function draw(){
    requestAnimationFrame(draw); t+=.005;
    const bg=ctx.createLinearGradient(0,0,W*.5,H);
    bg.addColorStop(0,'#01040f');bg.addColorStop(.4,'#020818');bg.addColorStop(.7,'#030b1e');bg.addColorStop(1,'#010612');
    ctx.fillStyle=bg;ctx.fillRect(0,0,W,H);
    NEBULAS.forEach((n,i)=>{
      const pulse=Math.sin(t*.35+i*1.3)*.01+n.alpha;
      const grd=ctx.createRadialGradient(n.cx*W,n.cy*H,0,n.cx*W,n.cy*H,Math.max(n.rx*W,n.ry*H));
      grd.addColorStop(0,`rgba(${n.color},${pulse})`);grd.addColorStop(.5,`rgba(${n.color},${pulse*.35})`);grd.addColorStop(1,`rgba(${n.color},0)`);
      ctx.save();ctx.translate(n.cx*W,n.cy*H);ctx.scale(1,n.ry/n.rx);ctx.beginPath();ctx.arc(0,0,n.rx*W,0,Math.PI*2);ctx.fillStyle=grd;ctx.fill();ctx.restore();
    });
    ORBS.forEach((o,i)=>{
      const pulse=Math.sin(t*.45+i*2.2)*.018+o.alpha;
      const grd=ctx.createRadialGradient(o.cx*W,o.cy*H,0,o.cx*W,o.cy*H,o.r);
      grd.addColorStop(0,`rgba(${o.color},${pulse*2.2})`);grd.addColorStop(.3,`rgba(${o.color},${pulse})`);grd.addColorStop(1,`rgba(${o.color},0)`);
      ctx.beginPath();ctx.arc(o.cx*W,o.cy*H,o.r,0,Math.PI*2);ctx.fillStyle=grd;ctx.fill();
    });
    stars.forEach(s=>{
      const dx=s.x-mouseX,dy=s.y-mouseY,dist=Math.sqrt(dx*dx+dy*dy);
      if(dist<REPEL_RADIUS&&dist>0){const force=(REPEL_RADIUS-dist)/REPEL_RADIUS;s.vx+=(dx/dist)*force*REPEL_FORCE/s.mass;s.vy+=(dy/dist)*force*REPEL_FORCE/s.mass;}
      s.vx+=(s.ox-s.x)*RETURN_FORCE;s.vy+=(s.oy-s.y)*RETURN_FORCE;s.vx*=FRICTION;s.vy*=FRICTION;s.x+=s.vx;s.y+=s.vy;
      const twinkle=Math.sin(t*s.twinkleSpeed+s.twinkleOffset)*.3+.7,speed=Math.sqrt(s.vx*s.vx+s.vy*s.vy),a=Math.min(1,s.alpha*twinkle+speed*.04);
      ctx.beginPath();ctx.arc(s.x,s.y,s.r*.5,0,Math.PI*2);ctx.fillStyle=`rgba(255,255,255,${a})`;ctx.fill();
      const grd=ctx.createRadialGradient(s.x,s.y,0,s.x,s.y,s.r*3);
      grd.addColorStop(0,`hsla(${s.hue},90%,88%,${a*.7})`);grd.addColorStop(1,`hsla(${s.hue},90%,70%,0)`);
      ctx.beginPath();ctx.arc(s.x,s.y,s.r*3,0,Math.PI*2);ctx.fillStyle=grd;ctx.fill();
    });
    for(let i=shooters.length-1;i>=0;i--){
      const s=shooters[i];s.progress+=s.speed;if(s.progress>=1){shooters.splice(i,1);continue;}
      const sx=s.x*W+Math.cos(s.angle)*s.progress*W*.55,sy=s.y*H+Math.sin(s.angle)*s.progress*W*.55;
      const ex=sx-Math.cos(s.angle)*s.len,ey=sy-Math.sin(s.angle)*s.len;
      const fade=s.progress<.2?s.progress/.2:1-(s.progress-.2)/.8;
      const grd=ctx.createLinearGradient(sx,sy,ex,ey);
      grd.addColorStop(0,`rgba(200,235,255,${s.alpha*fade})`);grd.addColorStop(.4,`rgba(91,200,245,${s.alpha*fade*.4})`);grd.addColorStop(1,'rgba(91,200,245,0)');
      ctx.beginPath();ctx.moveTo(sx,sy);ctx.lineTo(ex,ey);ctx.strokeStyle=grd;ctx.lineWidth=1.5;ctx.stroke();
      ctx.beginPath();ctx.arc(sx,sy,2,0,Math.PI*2);ctx.fillStyle=`rgba(220,245,255,${s.alpha*fade})`;ctx.fill();
    }
  }
  draw();
})();

