// ═══════════════════════════════════════════════════════════════════
let pct=0;
const ldFill=document.getElementById('ldFill'),ldPct=document.getElementById('ldPct'),ldTopline=document.getElementById('ldTopline'),ldWelcome=document.getElementById('ldWelcome');
function tick(){
  pct=Math.min(100,pct+Math.max(.5,(100-pct)*.025));
  ldFill.style.width=pct+'%';ldTopline.style.width=pct+'%';ldPct.textContent=Math.floor(pct);
  if(pct<100){setTimeout(tick,25);}else{ldFill.style.width='100%';ldPct.textContent='100';setTimeout(()=>{ldWelcome.textContent="You've Arrived in My Universe";ldWelcome.classList.add('show');setTimeout(launch,1200);},300);}
}
setTimeout(tick,400);
document.getElementById('navHome').classList.add('active');
function launch(){
  document.getElementById('loader').classList.add('ld-exit');
  setTimeout(()=>{document.getElementById('app').classList.add('show');document.getElementById('loader').style.display='none';initCardThumbs();initThree();},800);
}

