// PROJECT DETAIL
// ═══════════════════════════════════════════════════════════════════
function openDetail(i){
  const p=PROJECTS[i];
  document.getElementById('pd-crumb-name').textContent=p.name;
  document.getElementById('pd-index').textContent='PROJECT '+String(i+1).padStart(2,'0');
  const parts=p.name.split(' ');
  document.getElementById('pd-name').innerHTML='<span>'+parts[0]+'</span> '+parts.slice(1).join(' ');
  document.getElementById('pd-desc').textContent=p.desc;
  document.getElementById('pd-stack').innerHTML=p.stack.map(t=>{const url=TECH_LINKS[t];return url?`<a class="pd-stack-tag pd-stack-link" href="${url}" target="_blank" rel="noopener">${t}</a>`:`<span class="pd-stack-tag">${t}</span>`;}).join('');
  document.getElementById('pd-demo').href=p.demo;document.getElementById('pd-github').href=p.github;
  const imgEl=document.getElementById('pd-screenshot-img'),ph=document.getElementById('pd-shot-placeholder');
  if(p.screenshot){
    imgEl.style.display='block';imgEl.classList.remove('loaded');imgEl.src=p.screenshot;
    imgEl.onload=()=>imgEl.classList.add('loaded');ph.style.display='none';
    imgEl.style.cursor='zoom-in';
    imgEl.onclick=()=>window.openScreenshot&&window.openScreenshot(p.screenshot);
  }else{imgEl.style.display='none';imgEl.src='';ph.style.display='flex';imgEl.onclick=null;}
  document.getElementById('proj-grid-view').style.display='none';
  const dv=document.getElementById('proj-detail-view');dv.style.display='flex';dv.classList.remove('animating');void dv.offsetWidth;dv.classList.add('animating');setTimeout(()=>dv.classList.remove('animating'),800);bindHover();
}
function closeDetail(){document.getElementById('proj-detail-view').style.display='none';document.getElementById('proj-grid-view').style.display='flex';}

// ═══════════════════════════════════════════════════════════════════
// SCENE SETUP
// ═══════════════════════════════════════════════════════════════════
function setupScene(canvasId,isAbout){
  const canvas=document.getElementById(canvasId);if(!canvas)return null;
  const scene=new THREE.Scene();
  const w=canvas.clientWidth||500,h=canvas.clientHeight||700;
  const camera=new THREE.PerspectiveCamera(38,w/h,.1,100);
  camera.position.set(0,isAbout?1.6:0.5,2.0);camera.lookAt(0,isAbout?1.2:0.0,0);
  const renderer=new THREE.WebGLRenderer({canvas,antialias:true,alpha:true,powerPreference:'high-performance'});
  renderer.setSize(w,h);renderer.setPixelRatio(Math.min(window.devicePixelRatio,2));
  renderer.shadowMap.enabled=true;renderer.shadowMap.type=THREE.PCFSoftShadowMap;
  renderer.toneMapping=THREE.NoToneMapping;
  renderer.outputEncoding=THREE.sRGBEncoding;

  // Lighting tuned for astronaut mesh
  scene.add(new THREE.AmbientLight(0xffffff,2.2));
  const key=new THREE.DirectionalLight(0xffffff,2.5);key.position.set(3,5,5);key.castShadow=true;scene.add(key);
  const fill=new THREE.DirectionalLight(0x5bc8f5,1.2);fill.position.set(-4,2,3);scene.add(fill);
  const rim=new THREE.DirectionalLight(0x7dd8ff,1.0);rim.position.set(0,3,-4);scene.add(rim);
  const bot=new THREE.DirectionalLight(0xffffff,0.5);bot.position.set(0,-3,2);scene.add(bot);

  const partGeo=new THREE.BufferGeometry();
  const count=60,pos=new Float32Array(count*3);
  for(let i=0;i<count;i++){pos[i*3]=(Math.random()-.5)*4;pos[i*3+1]=(Math.random()-.5)*5;pos[i*3+2]=(Math.random()-.5)*2-.5;}
  partGeo.setAttribute('position',new THREE.BufferAttribute(pos,3));
  const partMat=new THREE.PointsMaterial({color:0x5bc8f5,size:.018,transparent:true,opacity:.4,blending:THREE.AdditiveBlending,depthWrite:false});
  scene.add(new THREE.Points(partGeo,partMat));

  return{scene,camera,renderer,canvas,partGeo,model:null,visorMesh:null,floatTime:Math.random()*100};
}


// ═══════════════════════════════════════════════════════════════════
// VISOR SHADER — cinematic space reflection on helmet glass
// Cyan/blue subtle elegant galaxy inside the visor
// ═══════════════════════════════════════════════════════════════════
function createVisorMesh(modelScale, modelPosY) {
  // Ellipsoid shaped to match the low-poly visor area
  const geo = new THREE.SphereGeometry(0.28, 32, 32);
  geo.scale(1.0, 0.72, 0.18); // flatten to match visor shape

  const mat = new THREE.ShaderMaterial({
    transparent: true,
    depthWrite: false,
    depthTest: true,
    side: THREE.FrontSide,
    blending: THREE.NormalBlending,
    uniforms: { uTime: { value: 0 } },
    vertexShader: `
      varying vec2 vUv;
      varying vec3 vNormal;
      varying vec3 vPos;
      void main(){
        vUv = uv;
        vNormal = normalize(normalMatrix * normal);
        vPos = position;
        gl_Position = projectionMatrix * modelViewMatrix * vec4(position, 1.0);
      }
    `,
    fragmentShader: `
      uniform float uTime;
      varying vec2 vUv;
      varying vec3 vNormal;
      varying vec3 vPos;

      float hash(vec2 p){ return fract(sin(dot(p, vec2(127.1,311.7))) * 43758.5453); }
      float hash(float n){ return fract(sin(n) * 43758.5453); }

      float noise(vec2 p){
        vec2 i = floor(p), f = fract(p);
        f = f*f*(3.0-2.0*f);
        return mix(mix(hash(i), hash(i+vec2(1,0)), f.x),
                   mix(hash(i+vec2(0,1)), hash(i+vec2(1,1)), f.x), f.y);
      }

      void main(){
        vec2 uv = vUv;

        // ── Dark space background ──
        vec3 col = vec3(0.01, 0.02, 0.06);

        // ── Nebula clouds — slow drift ──
        float t = uTime * 0.08;
        float n1 = noise(uv * 2.2 + vec2(t * 0.3, t * 0.15));
        float n2 = noise(uv * 3.5 - vec2(t * 0.18, t * 0.25));
        float nebula = pow(n1 * n2, 1.4) * 2.8;
        vec3 nebulaCol = mix(vec3(0.05, 0.18, 0.55), vec3(0.1, 0.55, 0.85), n1);
        col += nebulaCol * nebula * 0.45;

        // ── Moving stars ──
        vec2 starUv = uv * 18.0 + vec2(t * 0.12, t * 0.07);
        float starField = hash(floor(starUv));
        float starBright = smoothstep(0.97, 1.0, starField);
        // Twinkle
        float twinkle = sin(uTime * (starField * 4.0 + 1.5) + starField * 6.28) * 0.4 + 0.6;
        col += vec3(0.7, 0.92, 1.0) * starBright * twinkle * 1.8;

        // ── Small glowing planet (bottom-left of visor) ──
        vec2 planetPos = vec2(0.28, 0.3);
        float planetDist = length(uv - planetPos);
        float planet = smoothstep(0.095, 0.085, planetDist);
        // Planet surface
        float pNoise = noise(uv * 8.0 + vec2(t * 0.2, 0.0));
        vec3 planetCol = mix(vec3(0.1, 0.4, 0.9), vec3(0.05, 0.15, 0.5), pNoise);
        col += planetCol * planet;
        // Planet glow halo
        float glow = smoothstep(0.22, 0.08, planetDist) * 0.35;
        col += vec3(0.2, 0.6, 1.0) * glow;
        // Planet ring
        float ringDist = abs(planetDist - 0.135);
        float ring = smoothstep(0.018, 0.008, ringDist) * smoothstep(0.24, 0.1, planetDist) * 0.5;
        col += vec3(0.4, 0.75, 1.0) * ring;

        // ── Floating dust particles ──
        for(int i = 0; i < 6; i++){
          float fi = float(i);
          vec2 pPos = vec2(
            fract(hash(fi) + t * (0.04 + hash(fi+10.0)*0.06)),
            fract(hash(fi+3.7) + t * (0.02 + hash(fi+7.0)*0.04))
          );
          float pd = length(uv - pPos);
          col += vec3(0.5, 0.85, 1.0) * smoothstep(0.025, 0.0, pd) * 0.6;
        }

        // ── Cyan edge fresnel glow ──
        float fresnel = pow(1.0 - abs(dot(vNormal, vec3(0.0, 0.0, 1.0))), 2.5);
        col += vec3(0.1, 0.7, 1.0) * fresnel * 0.5;

        // ── Subtle glass reflection sheen ──
        float sheen = pow(max(0.0, dot(vNormal, normalize(vec3(1.0, 1.5, 1.0)))), 4.0);
        col += vec3(0.6, 0.88, 1.0) * sheen * 0.15;

        // ── Vignette — darker at edges, bright center ──
        vec2 vigUv = uv - 0.5;
        float vig = 1.0 - dot(vigUv, vigUv) * 1.8;
        col *= max(vig, 0.15);

        // ── Alpha — solid center, fade at edges ──
        float alpha = smoothstep(0.5, 0.2, length(uv - 0.5)) * 0.88 + 0.06;

        gl_FragColor = vec4(col, alpha);
      }
    `
  });

  const mesh = new THREE.Mesh(geo, mat);

  // Position exactly over visor area based on calculated world coords
  // Visor center: Y=0.196, Z=0.446, X=0
  // Adjust based on model position
  mesh.position.set(0.0, 0.20, 0.46);
  mesh.rotation.x = -0.12; // slight tilt matching helmet angle

  return mesh;
}

// ═══════════════════════════════════════════════════════════════════
// GLB LOADER
// ═══════════════════════════════════════════════════════════════════
function loadGLB(sc,isAbout,onDone){
  const loader=new THREE.GLTFLoader();
  loader.load('character.glb',
    (gltf)=>{
      const model=gltf.scene;

      // Fit model
      const box=new THREE.Box3().setFromObject(model);
      const size=box.getSize(new THREE.Vector3());
      const center=box.getCenter(new THREE.Vector3());

      // Scale large and close
      const scale=3.2/size.y;
      model.scale.setScalar(scale);

      // Center horizontally, shift up so head+chest is visible (crop legs)
      const scaledHeight=size.y*scale;
      model.position.set(
        -center.x*scale,
        -center.y*scale - 1.1, // slightly higher
        -center.z*scale
      );

      // Fix materials
      model.traverse(obj=>{
        if(obj.isMesh){
          obj.castShadow=true;obj.receiveShadow=true;
          const mats=Array.isArray(obj.material)?obj.material:[obj.material];
          mats.forEach(mat=>{
            if(mat.isMeshStandardMaterial||mat.isMeshPhysicalMaterial){
              mat.envMapIntensity=0;
              mat.needsUpdate=true;
            }
          });
        }
      });

      sc.scene.add(model);
      sc.model=model;

      // Create and attach visor shader mesh
      const visor = createVisorMesh(scale, model.position.y);
      model.add(visor); // attach to model so it floats with him
      sc.visorMesh = visor;

      // About page: face right toward the quote
      if(isAbout){
        model.rotation.y=0.3; // slightly toward quote
      }

      console.log('character.glb loaded ✓');
      if(onDone)onDone();
    },
    xhr=>{if(xhr.total)console.log('Loading:',Math.round(xhr.loaded/xhr.total*100)+'%');},
    err=>{console.error('character.glb failed — same folder as index.html?',err);if(onDone)onDone();}
  );
}

// ═══════════════════════════════════════════════════════════════════
// FLOAT ANIMATION — realistic zero-gravity layered sine waves
// ═══════════════════════════════════════════════════════════════════
function animateFloat(sc,dt,isAbout){
  if(!sc.model)return;
  sc.floatTime+=dt;
  const t=sc.floatTime;

  if(isAbout){
    // About: still, same position as home, just faces quote
    if(!sc._baseY) sc._baseY = sc.model.position.y;
    sc.model.position.y = sc._baseY; // lock Y position same as home
    return;
  }

  // Layered sine waves — different frequencies & amplitudes
  // so motion never perfectly repeats (looks truly random)
  const floatY =
    Math.sin(t*0.52)*0.072 +          // primary slow bob
    Math.sin(t*1.13+1.7)*0.028 +       // secondary faster
    Math.sin(t*0.29+3.1)*0.018;        // very slow drift

  const tiltZ =
    Math.sin(t*0.38+0.9)*0.028 +       // gentle side tilt
    Math.sin(t*0.91+2.3)*0.010;        // subtle wobble

  const tiltX =
    Math.sin(t*0.44+1.2)*0.022 +       // forward/back lean
    Math.sin(t*1.07+0.4)*0.008;        // micro-movement

  const driftY =                        // very slow Y rotation drift
    Math.sin(t*0.18+0.6)*0.055 +
    Math.sin(t*0.07+2.1)*0.025;

  sc.model.position.y += (floatY - (sc.model.position.y - sc._baseY||0) ) * 0.08;

  // Store base Y on first frame
  if(sc._baseY===undefined) sc._baseY=sc.model.position.y;
  sc.model.position.y = sc._baseY + floatY;

  sc.model.rotation.z = tiltZ;
  sc.model.rotation.x = tiltX;
  sc.model.rotation.y = driftY;

  // Update visor shader time
  if(sc.visorMesh && sc.visorMesh.material.uniforms){
    sc.visorMesh.material.uniforms.uTime.value = sc.floatTime;
  }

  // Float particles too
  const pos=sc.partGeo.attributes.position.array;
  for(let i=0;i<60;i++){
    pos[i*3+1]+=dt*(0.06+(i%7)*0.02);
    if(pos[i*3+1]>2.5)pos[i*3+1]=-2.5;
  }
  sc.partGeo.attributes.position.needsUpdate=true;
}

// ═══════════════════════════════════════════════════════════════════
// INIT THREE.JS
// ═══════════════════════════════════════════════════════════════════
function initThree(){
  if(typeof THREE==='undefined'){console.error('Three.js not loaded.');return;}
  if(typeof THREE.GLTFLoader!=='undefined'){startScenes();return;}
  const s=document.createElement('script');
  s.src='https://cdnjs.cloudflare.com/ajax/libs/three.js/r128/examples/js/loaders/GLTFLoader.min.js';
  s.onload=()=>{if(typeof THREE.GLTFLoader!=='undefined')startScenes();else loadFallback();};
  s.onerror=loadFallback;
  document.head.appendChild(s);
}
function loadFallback(){
  const s=document.createElement('script');
  s.src='https://cdn.jsdelivr.net/npm/three@0.128.0/examples/js/loaders/GLTFLoader.js';
  s.onload=startScenes;s.onerror=()=>console.error('GLTFLoader failed on both CDNs.');
  document.head.appendChild(s);
}
function startScenes(){
  const home=setupScene('three-canvas',false);
  if(!home)return;
  Object.assign(sceneHome,home);
  loadGLB(sceneHome,false,()=>startRenderLoop());
}

// ═══════════════════════════════════════════════════════════════════
// RENDER LOOP
// ═══════════════════════════════════════════════════════════════════
function startRenderLoop(){
  let lastTime=performance.now();
  function resize(sc){
    const w=sc.canvas.clientWidth,h=sc.canvas.clientHeight;
    if(sc.canvas.width!==w||sc.canvas.height!==h){sc.renderer.setSize(w,h,false);sc.camera.aspect=w/h;sc.camera.updateProjectionMatrix();}
  }
  function loop(){
    requestAnimationFrame(loop);
    const now=performance.now();const dt=Math.min((now-lastTime)/1000,.05);lastTime=now;globalTime+=dt;
    resize(sceneHome);
    animateFloat(sceneHome,dt,false);
    sceneHome.renderer.render(sceneHome.scene,sceneHome.camera);
  }
  loop();
}
